const KINDS = ["num","str","str","num","str","num","num","str","num","num","empty","str","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","empty","num","empty","empty","empty","empty","empty","empty","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","num","empty","num","num","num","num","num","num","num","num","empty","num","num","empty","empty","num","empty","empty","num","empty","empty","num","num","num","num","num","empty","str","str","str","str","str","str","empty"];

// Valor sintetico por columna: las de texto reciben placeholders seguros (sin PII);
// las numericas, un valor ficticio determinista y de magnitud plausible.
function syntheticValue(header, kind, i) {
  const h = (header ?? "").trim();
  if (kind === "empty") return undefined;
  if (kind === "str") {
    if (h === "Paciente") return "PACIENTE SINTETICO";
    if (h === "Género") return "Male";
    if (h === "Fecha de nacimiento") return "01-01-1990 00:00";
    if (h === "Measurement date") return "15-06-2026 10:00";
    if (h === "Cup Size") return "N/A";
    if (h === "Estatus") return "Analyzed";
    if (h === "Nombre de la aplicación") return "BiodyConnect android";
    if (h === "Version de la aplicación") return "1.1.4";
    return "N/A";
  }
  // numericas: casos humanos legibles dentro de rangos fisiologicos plausibles
  // (para que el fixture sea un export VALIDO frente a import-schema), el resto un
  // valor determinista pequeno y positivo (5..94) que pasa el limite global.
  if (h === "Peso kg") return 70;
  if (h === "Altura cm") return 170;
  if (h === "Edad") return 35;
  if (h === "Ángulo de fase a 50 kHz °") return 6.2;
  if (h === "Resistencia a 50khz Ohm") return 520;
  if (h === "Reactancia à 50khz Ohm") return 55;
  if (h.includes("Body Mass Index (BMI)") && h.includes("VALEURCALCULEE")) return 24.5;
  if (h === "#" || h.startsWith("# ") || h === "Identifiant de la mesure") return 100000 + i;
  return Math.round(((i * 37 + 13) % 90 + 5) * 100) / 100;
}

async function main() {
  const wb = new ExcelJS.Workbook();
  const ws = wb.addWorksheet("Measures");
  // exceljs es 1-based; construimos los arrays con un hueco en [0].
  const headerRow = [];
  const dataRow = [];
  for (let i = 1; i <= HEADERS.length; i++) {
    headerRow[i] = HEADERS[i - 1];
    dataRow[i] = syntheticValue(HEADERS[i - 1], KINDS[i - 1], i);
  }
  ws.getRow(1).values = headerRow;
  ws.getRow(2).values = dataRow;
  const dir = dirname(fileURLToPath(import.meta.url));
  const out = join(dir, "biody_synthetic.xlsx");
  await wb.xlsx.writeFile(out);
  console.log("fixture escrito:", out);
}

main().catch((e) => { console.error(e); process.exit(1); });
